const opps = $input.all().map(i => i.json);
const results = [];
const key = $env.GDA_WEBHOOK_HEADER_VALUE_V2;

for (const opp of opps) {
  try {
    const resp = await fetch('https://n8n.csr-llc.tech/webhook/gda-pwin-calculator', {
      method: 'POST',
      headers: { 'x-gda-key': key, 'Content-Type': 'application/json' },
      body: JSON.stringify({ action: 'calculate', opp_id: opp.id, opportunity_name: opp.opportunity_name, agency: opp.agency, value: opp.estimated_value, stage: opp.stage })
    });
    const data = await resp.json();
    results.push({ opp_id: opp.id, opp_name: opp.opportunity_name, agency: opp.agency, value: opp.estimated_value, pwin: data.pwin || data.score || data.gda_score || null, status: 'scored' });
  } catch(e) {
    results.push({ opp_id: opp.id, opp_name: opp.opportunity_name, status: 'error', error: e.message });
  }
}

return [{ json: { results, scored: results.filter(r=>r.status==='scored').length, errors: results.filter(r=>r.status==='error').length } }];

